// MARK: - Token Storage (Keychain-backed)

final class TokenStorage {
    static let shared = TokenStorage()
    
    private let accessTokenKey = "com.example.app.accessToken"
    private let refreshTokenKey = "com.example.app.refreshToken"
    
    private init() {}
    
    var accessToken: String? {
        get { readKeychain(key: accessTokenKey) }
        set {
            if let value = newValue {
                saveKeychain(key: accessTokenKey, value: value)
            } else {
                deleteKeychain(key: accessTokenKey)
            }
        }
    }
    
    var refreshToken: String? {
        get { readKeychain(key: refreshTokenKey) }
        set {
            if let value = newValue {
                saveKeychain(key: refreshTokenKey, value: value)
            } else {
                deleteKeychain(key: refreshTokenKey)
            }
        }
    }
    
    func clearTokens() {
        accessToken = nil
        refreshToken = nil
    }
    
    // MARK: - Keychain Helpers
    
    private func saveKeychain(key: String, value: String) {
        guard let data = value.data(using: .utf8) else { return }
        
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly
        ]
        
        // Delete any existing item first
        SecItemDelete(query as CFDictionary)
        
        var addQuery = query
        addQuery[kSecValueData as String] = data
        
        SecItemAdd(addQuery as CFDictionary, nil)
    }
    
    private func readKeychain(key: String) -> String? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        guard status == errSecSuccess, let data = result as? Data else {
            return nil
        }
        
        return String(data: data, encoding: .utf8)
    }
    
    private func deleteKeychain(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Certificate Pinning Delegate

final class CertificatePinningDelegate: NSObject, URLSessionDelegate {
    private let environment: Environment
    
    init(environment: Environment) {
        self.environment = environment
        super.init()
    }
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust,
              let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        // Always perform standard TLS validation first
        let policy = SecPolicyCreateSSL(true, challenge.protectionSpace.host as CFString)
        SecTrustSetPolicies(serverTrust, policy)
        
        var error: CFError?
        guard SecTrustEvaluateWithError(serverTrust, &error) else {
            // Standard TLS validation failed – reject
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // If the environment does not require pinning, accept after standard validation
        guard environment.requiresCertificatePinning else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        let pinnedHashes = environment.pinnedPublicKeyHashes
        guard !pinnedHashes.isEmpty else {
            // No pins configured but pinning is required – fail safe
            completionHandler(.cancelAuthenticationChallenge, nil)
            return
        }
        
        // Walk the certificate chain and check public key hashes
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        var pinMatched = false
        
        for index in 0..<certificateCount {
            guard let certificate = SecTrustCopyCertificateChain(serverTrust).map({ ($0 as! [SecCertificate])[index] }) else {
                continue
            }
            
            if let publicKeyHash = publicKeyHashForCertificate(certificate) {
                if pinnedHashes.contains(publicKeyHash) {
                    pinMatched = true
                    break
                }
            }
        }
        
        if pinMatched {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        } else {
            completionHandler(.cancelAuthenticationChallenge, nil)
        }
    }
    
    // MARK: - SPKI Hash Extraction
    
    private func publicKeyHashForCertificate(_ certificate: SecCertificate) -> String? {
        guard let publicKey = SecCertificateCopyKey(certificate) else {
            return nil
        }
        
        var error: Unmanaged<CFError>?
        guard let publicKeyData = SecKeyCopyExternalRepresentation(publicKey, &error) as Data? else {
            return nil
        }
        
        // Build the SPKI header based on key type/size so we hash the full
        // SubjectPublicKeyInfo structure (matching the standard pin format).
        let spkiHeader = spkiHeaderForKey(publicKey)
        var spkiData = Data(spkiHeader)
        spkiData.append(publicKeyData)
        
        // SHA-256 hash, base64-encoded
        let hash = sha256(data: spkiData)
        return hash.base64EncodedString()
    }
    
    private func spkiHeaderForKey(_ key: SecKey) -> [UInt8] {
        guard let attributes = SecKeyCopyAttributes(key) as? [String: Any],
              let keyType = attributes[kSecAttrKeyType as String] as? String,
              let keySize = attributes[kSecAttrKeySizeInBits as String] as? Int else {
            return rsa2048SPKIHeader
        }
        
        if keyType == (kSecAttrKeyTypeRSA as String) {
            switch keySize {
            case 2048: return rsa2048SPKIHeader
            case 4096: return rsa4096SPKIHeader
            default:   return rsa2048SPKIHeader
            }
        } else if keyType == (kSecAttrKeyTypeECSECPrimeRandom as String) {
            switch keySize {
            case 256: return ecDsaSecp256r1SPKIHeader
            case 384: return ecDsaSecp384r1SPKIHeader
            default:  return ecDsaSecp256r1SPKIHeader
            }
        }
        
        return rsa2048SPKIHeader
    }
    
    // ASN.1 DER headers for common key types
    private let rsa2048SPKIHeader: [UInt8] = [
        0x30, 0x82, 0x01, 0x22, 0x30, 0x0d, 0x06, 0x09,
        0x2a, 0x86, 0x48, 0x86, 0xf7, 0x0d, 0x01, 0x01,
        0x01, 0x05, 0x00, 0x03, 0x82, 0x01, 0x0f, 0x00
    ]
    
    private let rsa4096SPKIHeader: [UInt8] = [
        0x30, 0x82, 0x02, 0x22, 0x30, 0x0d, 0x06, 0x09,
        0x2a, 0x86, 0x48, 0x86, 0xf7, 0x0d, 0x01, 0x01,
        0x01, 0x05, 0x00, 0x03, 0x82, 0x02, 0x0f, 0x00
    ]
    
    private let ecDsaSecp256r1SPKIHeader: [UInt8] = [
        0x30, 0x59, 0x30, 0x13, 0x06, 0x07, 0x2a, 0x86,
        0x48, 0xce, 0x3d, 0x02, 0x01, 0x06, 0x08, 0x2a,
        0x86, 0x48, 0xce, 0x3d, 0x03, 0x01, 0x07, 0x03,
        0x42, 0x00
    ]
    
    private let ecDsaSecp384r1SPKIHeader: [UInt8] = [
        0x30, 0x76, 0x30, 0x10, 0x06, 0x07, 0x2a, 0x86,
        0x48, 0xce, 0x3d, 0x02, 0x01, 0x06, 0x05, 0x2b,
        0x81, 0x04, 0x00, 0x22, 0x03, 0x62, 0x00
    ]
    
    private func sha256(data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: 32)
        data.withUnsafeBytes { buffer in
            _ = CC_SHA256(buffer.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
}

