// MARK: - Network Client

final class NetworkClient {
    static let shared = NetworkClient()
    
    private let environment: Environment
    private let session: URLSession
    private let pinningDelegate: CertificatePinningDelegate
    private let decoder: JSONDecoder
    private let encoder: JSONEncoder
    private let tokenStorage = TokenStorage.shared
    
    // Serialise token refresh to avoid races
    private let refreshLock = NSLock()
    private var isRefreshing = false
    private var refreshCompletionHandlers: [(Result<String, NetworkError>) -> Void] = []
    
    init(environment: Environment = .production) {
        self.environment = environment
        self.pinningDelegate = CertificatePinningDelegate(environment: environment)
        
        let configuration = URLSessionConfiguration.default
        configuration.timeoutIntervalForRequest = 30
        configuration.timeoutIntervalForResource = 60
        configuration.waitsForConnectivity = true
        configuration.tlsMinimumSupportedProtocolVersion = .TLSv12
        
        self.session = URLSession(
            configuration: configuration,
            delegate: pinningDelegate,
            delegateQueue: nil
        )
        
        self.decoder = JSONDecoder()
        self.decoder.keyDecodingStrategy = .convertFromSnakeCase
        
        self.encoder = JSONEncoder()
        self.encoder.keyEncodingStrategy = .convertToSnakeCase
    }
    
    // MARK: - Public API
    
    func login(email: String, password: String) async throws -> AuthResponse {
        let body = LoginRequest(email: email, password: password)
        let response: AuthResponse = try await request(
            endpoint: .login,
            body: body
        )
        tokenStorage.accessToken = response.accessToken
        tokenStorage.refreshToken = response.refreshToken
        return response
    }
    
    func register(email: String, password: String, name: String) async throws -> AuthResponse {
        let body = RegisterRequest(email: email, password: password, name: name)
        let response: AuthResponse = try await request(
            endpoint: .register,
            body: body
        )
        tokenStorage.accessToken = response.accessToken
        tokenStorage.refreshToken = response.refreshToken
        return response
    }
    
    func fetchCurrentUser() async throws -> User {
        return try await authenticatedRequest(endpoint: .userProfile)
    }
    
    func fetchUsers(page: Int = 1, perPage: Int = 20) async throws -> UsersResponse {
        let queryItems = [
            URLQueryItem(name: "page", value: String(page)),
            URLQueryItem(name: "per_page", value: String(perPage))
        ]
        return try await authenticatedRequest(
            endpoint: .users,
            queryItems: queryItems
        )
    }
    
    func logout() {
        tokenStorage.clearTokens()
    }
    
    // MARK: - Core Request Methods
    
    private func request<T: Decodable, B: Encodable>(
        endpoint: APIEndpoint,
        body: B? = nil as String?,
        queryItems: [URLQueryItem]? = nil,
        additionalHeaders: [String: String]? = nil
    ) async throws -> T {
        let urlRequest = try buildRequest(
            endpoint: endpoint,
            body: body,
            queryItems: queryItems,
            additionalHeaders: additionalHeaders
        )
        return try await execute(urlRequest)
    }
    
    private func request<T: Decodable>(
        endpoint: APIEndpoint,
        queryItems: [URLQueryItem]? = nil,
        additionalHeaders: [String: String]? = nil
    ) async throws -> T {
        let urlRequest = try buildRequest(
            endpoint: endpoint,
            body: nil as String?,
            queryItems: queryItems,
            additionalHeaders: additionalHeaders
        )
        return try await execute(urlRequest)
    }
    
    private func authenticatedRequest<T: Decodable>(
        endpoint: APIEndpoint,
        queryItems: [URLQueryItem]? = nil
    ) async throws -> T {
        guard let accessToken = tokenStorage.accessToken else {
            throw NetworkError.unauthorized
        }
        
        let headers = ["Authorization": "Bearer \(accessToken)"]
        
        do {
            return try await request(
                endpoint: endpoint,
                queryItems: queryItems,
                additionalHeaders: headers
            )
        } catch NetworkError.unauthorized {
            // Attempt token refresh
            let newToken = try await refreshAccessToken()
            let retryHeaders = ["Authorization": "Bearer \(newToken)"]
            return try await request(
                endpoint: endpoint,
                queryItems: queryItems,
                additionalHeaders: retryHeaders
            )
        }
    }
    
    private func authenticatedRequest<T: Decodable, B: Encodable>(
        endpoint: APIEndpoint,
        body: B,
        queryItems: [URLQueryItem]? = nil
    ) async throws -> T {
        guard let accessToken = tokenStorage.accessToken else {
            throw NetworkError.unauthorized
        }
        
        let headers = ["Authorization": "Bearer \(accessToken)"]
        
        do {
            return try await request(
                endpoint: endpoint,
                body: body,
                queryItems: queryItems,
                additionalHeaders: headers
            )
        } catch NetworkError.unauthorized {
            let newToken = try await refreshAccessToken()
            let retryHeaders = ["Authorization": "Bearer \(newToken)"]
            return try await request(
                endpoint: endpoint,
                body: body,
                queryItems: queryItems,
                additionalHeaders: retryHeaders
            )
        }
    }
    
    // MARK: - Request Building
    
    private func buildRequest<B: Encodable>(
        endpoint: APIEndpoint,
        body: B?,
        queryItems: [URLQueryItem]?,
        additionalHeaders: [String: String]?
    ) throws -> URLRequest {
        guard var components = URLComponents(string: environment.baseURL + endpoint.path) else {
            throw NetworkError.invalidURL
        }
        
        if let queryItems = queryItems, !queryItems.isEmpty {
            components.queryItems = queryItems
        }
        
        guard let url = components.url else {
            throw NetworkError.invalidURL
        }
        
        var urlRequest = URLRequest(url: url)
        urlRequest.httpMethod = endpoint.method.rawValue
        urlRequest.setValue("application/json", forHTTPHeaderField: "Content-Type")
        urlRequest.setValue("application/json", forHTTPHeaderField: "Accept")
        
        additionalHeaders?.forEach { key, value in
            urlRequest.setValue(value, forHTTPHeaderField: key)
        }
        
        if let body = body, endpoint.method == .post || endpoint.method == .put {
            urlRequest.httpBody = try encoder.encode(body)
        }
        
        return urlRequest
    }
    
    // MARK: - Request Execution
    
    private func execute<T: Decodable>(_ request: URLRequest) async throws -> T {
        let data: Data
        let response: URLResponse
        
        do {
            (data, response) = try await session.data(for: request)
        } catch let urlError as URLError {
            if urlError.code == .cancelled || urlError.code == .serverCertificateUntrusted ||
               urlError.code == .serverCertificateHasBadDate || urlError.code == .serverCertificateNotYetValid ||
               urlError.code == .serverCertificateHasUnknownRoot || urlError.code == .clientCertificateRejected {
                throw NetworkError.certificatePinningFailed
            }
            if urlError.code == .notConnectedToInternet || urlError.code == .networkConnectionLost {
                throw NetworkError.networkUnavailable
            }
            throw NetworkError.unknown(urlError)
        } catch {
            throw NetworkError.unknown(error)
        }
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw NetworkError.noData
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            do {
                let decoded = try decoder.decode(T.self, from: data)
                return decoded
            } catch {
                throw NetworkError.decodingError(error)
            }
        case 401:
            throw NetworkError.unauthorized
        default:
            throw NetworkError.serverError(statusCode: httpResponse.statusCode, data: data)
        }
    }
    
    // MARK: - Token Refresh
    
    private func refreshAccessToken() async throws -> String {
        return try await withCheckedThrowingContinuation { continuation in
            refreshLock.lock()
            
            refreshCompletionHandlers.append { result in
                continuation.resume(with: result)
            }
            
            guard !isRefreshing else {
                refreshLock.unlock()
                return
            }
            
            isRefreshing = true
            refreshLock.unlock()
            
            Task { [weak self] in
                guard let self = self else { return }
                
                do {
                    guard let refreshToken = self.tokenStorage.refreshToken else {
                        throw NetworkError.unauthorized
                    }
                    
                    let body = ["refresh_token": refreshToken]
                    let response: AuthResponse = try await self.request(
                        endpoint: .refreshToken,
                        body: body
                    )
                    
                    self.tokenStorage.accessToken = response.accessToken
                    self.tokenStorage.refreshToken = response.refreshToken
                    
                    self.refreshLock.lock()
                    self.isRefreshing = false
                    let handlers = self.refreshCompletionHandlers
                    self.refreshCompletionHandlers.removeAll()
                    self.refreshLock.unlock()
                    
                    handlers.forEach { $0(.success(response.accessToken)) }
                    
                } catch {
                    self.tokenStorage.clearTokens()
                    
                    self.refreshLock.lock()
                    self.isRefreshing = false
                    let handlers = self.refreshCompletionHandlers
                    self.refreshCompletionHandlers.removeAll()
                    self.refreshLock.unlock()
                    
                    let networkError = (error as? NetworkError) ?? .unknown(error)
                    handlers.forEach { $0(.failure(networkError)) }
                }
            }
        }
    }
}

